import{c as d,Q as o,j as i,m as e}from"./chunks/framework.D0Y1hua4.js";const b=JSON.parse('{"title":"好工作是找出来的还是干出来的","description":"","frontmatter":{},"headers":[],"relativePath":"notes/培训/Meeting/好工作是找出来的还是干出来的.md","filePath":"notes/培训/Meeting/好工作是找出来的还是干出来的.md"}'),a={name:"notes/培训/Meeting/好工作是找出来的还是干出来的.md"};function t(p,r,n,l,s,x){return o(),i("div",null,[...r[0]||(r[0]=[e('<h1 id="好工作是找出来的还是干出来的" tabindex="-1">好工作是找出来的还是干出来的 <a class="header-anchor" href="#好工作是找出来的还是干出来的" aria-label="Permalink to &quot;好工作是找出来的还是干出来的&quot;">​</a></h1><div style="margin:20px 0;"><h3 id="👑-一、好工作是-找出来-的-特定人群的特权" tabindex="-1">👑 一、好工作是&quot;找出来&quot;的：特定人群的特权 <a class="header-anchor" href="#👑-一、好工作是-找出来-的-特定人群的特权" aria-label="Permalink to &quot;👑 一、好工作是&quot;找出来&quot;的：特定人群的特权&quot;">​</a></h3><div style="display:flex;flex-wrap:wrap;gap:12px;margin-top:12px;"><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:2em;margin-bottom:8px;">🏛️</div><strong>有特殊家庭背景的人</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><p>例如父母是官员、企业家或拥有强大关系网，可以轻松安排进入体制内或优质单位。</p></div></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:2em;margin-bottom:8px;">🎓</div><strong>有良好教育背景的人</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><p>父母是高知分子，不仅能提供优质的教育使其获得高学历，还能利用自己的圈层资源为子女介绍工作。</p></div></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:2em;margin-bottom:8px;">🔑</div><strong>&quot;口含金钥匙&quot;的富二代</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><p>家产丰厚，工作更多是体验生活，最终目标是继承家业。</p></div></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:2em;margin-bottom:8px;">🎖️</div><strong>享有父辈荣誉的人</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><p>例如父母是军人、英模等，国家或单位会给予相应的照顾和安排。</p></div></div></div></div><div style="margin:20px 0;"><h3 id="💪-二、好工作是-干出来-的-普通人的唯一出路" tabindex="-1">💪 二、好工作是&quot;干出来&quot;的：普通人的唯一出路 <a class="header-anchor" href="#💪-二、好工作是-干出来-的-普通人的唯一出路" aria-label="Permalink to &quot;💪 二、好工作是&quot;干出来&quot;的：普通人的唯一出路&quot;">​</a></h3><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;margin-top:12px;color:#333;"><p>对于绝大多数没有上述背景的普通人（父母是普通工人、农民，自己学历一般）来说，几乎不可能&quot;找到&quot;世俗意义上的好工作。唯一的途径是：<strong>把一份普通的工作，干成不普通的事业。</strong></p></div><div style="display:flex;flex-wrap:wrap;gap:12px;margin-top:12px;"><div style="flex:1;min-width:250px;background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:1.5em;margin-bottom:8px;">😰</div><strong>核心困境</strong><div style="background:rgba(239,68,68,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #ef4444;"><p>普通人去应聘一些&quot;好单位&quot;（如大厂、政府部门），可能连学历门槛都达不到。</p><blockquote style="margin:0 0 8px 0;padding:8px 12px;border-left:3px solid #667eea;background:rgba(102,126,234,0.05);border-radius:4px;color:#555;">张雪峰：那些世界500强的企业都在说学历不重要，但它们从来不会去一个大专校招。</blockquote></div></div><div style="flex:1;min-width:250px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:1.5em;margin-bottom:8px;">🚀</div><strong>核心出路</strong><div style="background:rgba(34,197,94,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #22c55e;"><p>必须通过自身的努力，在普通的岗位上创造超凡的价值。</p></div></div></div></div><div style="margin:20px 0;"><h3 id="🎯-三、如何-干出来-选择大于努力-态度决定上限" tabindex="-1">🎯 三、如何&quot;干出来&quot;：选择大于努力，态度决定上限 <a class="header-anchor" href="#🎯-三、如何-干出来-选择大于努力-态度决定上限" aria-label="Permalink to &quot;🎯 三、如何&quot;干出来&quot;：选择大于努力，态度决定上限&quot;">​</a></h3><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;margin-top:12px;color:#333;"><p>并非所有工作都能&quot;干&quot;出前途。复制经验看前提。</p></div><h4 id="_1-选择有-前景-的工作平台" tabindex="-1">1. 选择有&quot;前景&quot;的工作平台 <a class="header-anchor" href="#_1-选择有-前景-的工作平台" aria-label="Permalink to &quot;1. 选择有&quot;前景&quot;的工作平台&quot;">​</a></h4><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;margin-top:12px;color:#333;"><p>一个能让你把工作&quot;干出来&quot;的平台，必须具备以下机制：</p><div style="display:flex;flex-wrap:wrap;gap:12px;margin-top:12px;"><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><div style="font-size:1.5em;">🏢</div><strong>企业规模与抗风险能力</strong><p>公司需有足够大的规模和实力，能够长期经营，提供稳定的发展空间，而非一个短期项目。</p><blockquote style="margin:0 0 8px 0;padding:8px 12px;border-left:3px solid #667eea;background:rgba(102,126,234,0.05);border-radius:4px;color:#555;">疫情期间总部补贴，从公司到个人。</blockquote></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><div style="font-size:1.5em;">⚖️</div><strong>公平的晋升机制</strong><p>晋升标准必须清晰、公平、透明，靠能力和业绩说话，而非关系。</p></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><div style="font-size:1.5em;">💰</div><strong>有吸引力的利润分配机制</strong><p>公司愿意与核心员工分享发展成果（例如，成为经理后可以带走团队相当比例的利润），而非老板独占。</p></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><div style="font-size:1.5em;">🌍</div><strong>可复制的开拓模式</strong><p>公司鼓励和支持有能力的员工去开拓新市场、成立新公司，为人才提供无限的发展舞台。</p></div></div></div><h4 id="_2-拥有-干事业-的态度" tabindex="-1">2. 拥有&quot;干事业&quot;的态度 <a class="header-anchor" href="#_2-拥有-干事业-的态度" aria-label="Permalink to &quot;2. 拥有&quot;干事业&quot;的态度&quot;">​</a></h4><div style="display:flex;flex-wrap:wrap;gap:12px;margin-top:12px;"><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:1.5em;margin-bottom:8px;">🔥</div><strong>从&quot;工作&quot;到&quot;事业&quot;</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><p>不能仅以打工的心态应付，而要将工作视为自己的事业，全力以赴。</p></div></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:1.5em;margin-bottom:8px;">👊</div><strong>&quot;打死都要&quot;的决心</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><p>要有不达目的不罢休的倔强和坚持，将全部时间和精力聚焦在一件事情上，持续深耕。</p></div></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:1.5em;margin-bottom:8px;">🚫</div><strong>拒绝&quot;混日子&quot;</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><p>以结果为导向，而不是用&quot;熬时间&quot;来自我安慰。别人在同样的机制下能晋升、能创业成功，自己若还在原地，核心原因在于是否真的用心和努力。</p></div></div></div></div><div style="margin:20px 0;"><h3 id="📖-四、亲身经历" tabindex="-1">📖 四、亲身经历 <a class="header-anchor" href="#📖-四、亲身经历" aria-label="Permalink to &quot;📖 四、亲身经历&quot;">​</a></h3><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;margin-top:12px;color:#333;"><p>邓总从一个KTV服务员、只有高中学历的精神小伙变成一家公司的经理。</p></div><div style="display:flex;flex-wrap:wrap;gap:12px;margin-top:12px;align-items:stretch;"><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;display:flex;flex-direction:column;"><div style="font-size:2em;margin-bottom:8px;">📍</div><strong>起点</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;flex:1;border-left:4px solid #667eea;"><p>没有背景和学历，从最基层的销售（扫楼、陌拜）干起。</p></div></div><div style="flex:0 0 auto;display:flex;align-items:center;font-size:2em;color:#667eea;padding:0 4px;">→</div><div style="flex:1;min-width:200px;background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);border-radius:12px;padding:16px;color:#333;display:flex;flex-direction:column;"><div style="font-size:2em;margin-bottom:8px;">🔄</div><strong>转折</strong><div style="background:rgba(245,158,11,0.08);padding:12px;border-radius:8px;margin-top:8px;flex:1;border-left:4px solid #f59e0b;"><p>加入现在的公司，因为这里的机制（公平晋升、利润共享、全国开拓）给了他这样的普通人&quot;干出来&quot;的机会。</p></div></div><div style="flex:0 0 auto;display:flex;align-items:center;font-size:2em;color:#667eea;padding:0 4px;">→</div><div style="flex:1;min-width:200px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);border-radius:12px;padding:16px;color:#333;display:flex;flex-direction:column;"><div style="font-size:2em;margin-bottom:8px;">🌟</div><strong>现状</strong><div style="background:rgba(34,197,94,0.08);padding:12px;border-radius:8px;margin-top:8px;flex:1;border-left:4px solid #22c55e;"><p>通过努力，从普通业务员成长为经理，实现了收入和生活品质的跃迁。</p></div></div></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:20px 0;color:#333;text-align:center;"><h3 id="🏆-总结" tabindex="-1">🏆 总结 <a class="header-anchor" href="#🏆-总结" aria-label="Permalink to &quot;🏆 总结&quot;">​</a></h3><div style="background:rgba(102,126,234,0.08);padding:16px;border-radius:8px;margin-top:12px;text-align:left;font-size:1.05em;border-left:4px solid #667eea;"><p>认清现实，放弃不切实际的幻想。对于没有特殊背景的普通人而言，通往&quot;好工作&quot;乃至&quot;好事业&quot;的道路，在于<strong>选择一个拥有良性机制的平台</strong>，并在此平台上<strong>以&quot;干事业&quot;的态度进行长期的、极致努力的投入</strong>。成功不在于你找到了什么，而在于你在选对的地方，最终干成了什么。</p></div></div>',6)])])}const u=d(a,[["render",t]]);export{b as __pageData,u as default};
